package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Account.AccountId;
import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.domain.model.ActivityWindow;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.CancelTransfersUseCase;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import io.reflectoring.buckpal.application.port.out.UpdateAccountStatePort;
import io.reflectoring.buckpal.common.UseCase;

import java.time.LocalDateTime;
import java.util.List;

@UseCase
public class CancelTransfersService implements CancelTransfersUseCase {
    private final LoadAccountPort loadAccountPort;
    private final UpdateAccountStatePort updateAccountStatePort;

    public CancelTransfersService(LoadAccountPort loadAccountPort, UpdateAccountStatePort updateAccountStatePort) {
        this.loadAccountPort = loadAccountPort;
        this.updateAccountStatePort = updateAccountStatePort;
    }

    @Override
    public boolean cancelTransfers(CancelTransfersCommand command) {
        LocalDateTime cutoffTime = command.cutoffTime();
        List<AccountId> transferIds = command.transferIds();

        for (AccountId accountId : transferIds) {
            Account account = loadAccountPort.loadAccount(accountId, cutoffTime);
            if (account == null) {
                continue;
            }

            ActivityWindow activityWindow = account.getActivityWindow();
            List<Activity> activities = activityWindow.getActivities();

            for (Activity activity : activities) {
                if (activity.getTimestamp().isAfter(cutoffTime.minusHours(1)) && activity.getTimestamp().isBefore(cutoffTime)) {
                    Account sourceAccount = loadAccountPort.loadAccount(activity.getSourceAccountId(), cutoffTime);
                    Account targetAccount = loadAccountPort.loadAccount(activity.getTargetAccountId(), cutoffTime);

                    if (sourceAccount != null && targetAccount != null) {
                        Money money = activity.getMoney();
                        sourceAccount.deposit(money, activity.getSourceAccountId());
                        targetAccount.withdraw(money, activity.getTargetAccountId());
                        updateAccountStatePort.updateActivities(sourceAccount);
                        updateAccountStatePort.updateActivities(targetAccount);
                    }
                }
            }
        }
        return true;
    }
}

