package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.CancelTransfersUseCase;
import io.reflectoring.buckpal.application.port.out.LoadActivitiesPort;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import io.reflectoring.buckpal.application.port.out.RemoveActivityPort;
import io.reflectoring.buckpal.application.port.out.UpdateAccountStatePort;
import io.reflectoring.buckpal.common.UseCase;

import java.time.LocalDateTime;
import java.util.List;

@UseCase
public class CancelTransfersService implements CancelTransfersUseCase {

    private final LoadActivitiesPort loadActivitiesPort;
    private final LoadAccountPort loadAccountPort;
    private final UpdateAccountStatePort updateAccountStatePort;
    private final RemoveActivityPort removeActivityPort;

    public CancelTransfersService(
            LoadActivitiesPort loadActivitiesPort,
            LoadAccountPort loadAccountPort,
            UpdateAccountStatePort updateAccountStatePort,
            RemoveActivityPort removeActivityPort) {
        this.loadActivitiesPort = loadActivitiesPort;
        this.loadAccountPort = loadAccountPort;
        this.updateAccountStatePort = updateAccountStatePort;
        this.removeActivityPort = removeActivityPort;
    }

    @Override
    public boolean cancelTransfers() {
        LocalDateTime oneHourAgo = LocalDateTime.now().minusHours(1);
        List<Activity> recentActivities = loadActivitiesPort.loadRecentActivities(oneHourAgo);

        if (recentActivities.isEmpty()) {
            return false;
        }

        for (Activity activity : recentActivities) {
            removeActivityPort.removeActivity(activity.getId());
        }

        recentActivities.forEach(activity -> {
            var sourceAccount = loadAccountPort.loadAccount(activity.getSourceAccountId(), LocalDateTime.now());
            var targetAccount = loadAccountPort.loadAccount(activity.getTargetAccountId(), LocalDateTime.now());

            Money transferAmount = activity.getMoney();

            sourceAccount.deposit(transferAmount, activity.getSourceAccountId());
            targetAccount.withdraw(transferAmount, activity.getTargetAccountId());

            updateAccountStatePort.updateActivities(sourceAccount);
            updateAccountStatePort.updateActivities(targetAccount);
        });

        return true;
    }
}

