package io.reflectoring.buckpal.adapter.out.persistence;

import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.port.out.LoadActivitiesPort;
import io.reflectoring.buckpal.common.PersistenceAdapter;
import org.springframework.data.jpa.repository.JpaRepository;

import java.time.LocalDateTime;
import java.util.List;

@PersistenceAdapter
public class ActivityPersistenceAdapter implements LoadActivitiesPort {

    private final SpringDataActivityRepository activityRepository;
    private final ActivityMapper activityMapper;

    public ActivityPersistenceAdapter(
            SpringDataActivityRepository activityRepository,
            ActivityMapper activityMapper) {
        this.activityRepository = activityRepository;
        this.activityMapper = activityMapper;
    }

    @Override
    public List<Activity> loadRecentActivities(LocalDateTime since) {
        return activityRepository.findByTimestampAfter(since)
                .stream()
                .map(activityMapper::mapToDomainEntity)
                .toList();
    }
}

