import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.domain.model.ActivityWindow;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.common.WebAdapter;

import java.math.BigInteger;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

@WebAdapter
public final class AccountDtoMapper {

    public static AccountDto mapToDto(Account account) {
        return new AccountDto(
                account.getId().map(AccountId::getValue).orElse(null),
                account.getBaselineBalance().getAmount(),
                mapActivityWindowToDto(account.getActivityWindow())
        );
    }

    public static Account mapToDomain(AccountDto accountDto) {
        AccountId accountId = accountDto.accountId() != null ? new AccountId(accountDto.accountId()) : null;
        Money baselineBalance = new Money(accountDto.baselineBalance());
        ActivityWindow activityWindow = mapActivityWindowToDomain(accountDto.activityWindow());
        return Account.withId(accountId, baselineBalance, activityWindow);
    }

    private static ActivityWindowDto mapActivityWindowToDto(ActivityWindow activityWindow) {
        return new ActivityWindowDto(
                activityWindow.getActivities().stream()
                        .map(activity -> new ActivityDto(
                                activity.getId().getValue(),
                                activity.getMoney().getAmount(),
                                activity.getOwnerAccountId().getValue(),
                                activity.getSourceAccountId().getValue(),
                                activity.getTargetAccountId().getValue(),
                                activity.getTimestamp()
                        ))
                        .collect(Collectors.toList())
        );
    }

    private static ActivityWindow mapActivityWindowToDomain(ActivityWindowDto activityWindowDto) {
        List<Activity> activities = activityWindowDto.activities().stream()
                .map(activityDto -> new Activity(
                        new AccountId(activityDto.ownerAccountId()),
                        new AccountId(activityDto.sourceAccountId()),
                        new AccountId(activityDto.targetAccountId()),
                        activityDto.timestamp(),
                        new Money(activityDto.money())
                ))
                .collect(Collectors.toList());
        return new ActivityWindow(activities);
    }

    public record AccountDto(Long accountId, BigInteger baselineBalance, ActivityWindowDto activityWindow) {}

    public record ActivityWindowDto(List<ActivityDto> activities) {}

    public record ActivityDto(
            Long id,
            BigInteger money,
            Long ownerAccountId,
            Long sourceAccountId,
            Long targetAccountId,
            LocalDateTime timestamp
    ) {}
}

