package io.reflectoring.buckpal.adapter.in.web;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Account.AccountId;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.common.WebAdapter;
import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.domain.model.Activity.ActivityId;
import io.reflectoring.buckpal.application.domain.model.ActivityWindow;

@WebAdapter
public final class AccountDtoMapper {

    public AccountDto toDto(Account account) {
        return new AccountDto(
                account.getId().map(AccountId::getValue).orElse(null),
                account.getBaselineBalance().getAmount(),
                account.getActivityWindow().getActivities().stream()
                        .map(activity -> new AccountDto.ActivityDto(
                                activity.getId().getValue(),
                                activity.getOwnerAccountId().getValue(),
                                activity.getSourceAccountId().getValue(),
                                activity.getTargetAccountId().getValue(),
                                activity.getTimestamp(),
                                activity.getMoney().getAmount()
                        ))
                        .toList()
        );
    }

    public Account toDomain(AccountDto accountDto) {
        AccountId accountId = new AccountId(accountDto.accountId());
        Money baselineBalance = new Money(accountDto.baselineBalance());
        Account.AccountId ownerAccountId = new AccountId(accountDto.activities().get(0).ownerAccountId());
        Account.AccountId sourceAccountId = new AccountId(accountDto.activities().get(0).sourceAccountId());
        Account.AccountId targetAccountId = new AccountId(accountDto.activities().get(0).targetAccountId());
        java.time.LocalDateTime timestamp = accountDto.activities().get(0).timestamp();
        Money money = new Money(accountDto.activities().get(0).moneyAmount());

        Account.ActivityWindow activityWindow = new Account.ActivityWindow(
                accountDto.activities().stream()
                        .map(activity -> new Account.Activity(
                                new Account.Activity.ActivityId(activity.activityId()),
                                ownerAccountId,
                                sourceAccountId,
                                targetAccountId,
                                timestamp,
                                money
                        ))
                        .toList()
        );

        return Account.withId(accountId, baselineBalance, activityWindow);
    }

    public record AccountDto(
            Long accountId,
            java.math.BigInteger baselineBalance,
            java.util.List<ActivityDto> activities
    ) {
        public record ActivityDto(
                Long activityId,
                Long ownerAccountId,
                Long sourceAccountId,
                Long targetAccountId,
                java.time.LocalDateTime timestamp,
                java.math.BigInteger moneyAmount
        ) {}
    }
}

package io.reflectoring.buckpal.adapter.in.web;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.SendMoneyCommand;
import io.reflectoring.buckpal.application.port.in.SendMoneyUseCase;
import io.reflectoring.buckpal.common.WebAdapter;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

@WebAdapter
@RestController
public class SendMoneyController {

    private final SendMoneyUseCase sendMoneyUseCase;

    public SendMoneyController(SendMoneyUseCase sendMoneyUseCase) {
        this.sendMoneyUseCase = sendMoneyUseCase;
    }

    @PostMapping("/accounts/send/{sourceAccountId}/{targetAccountId}/{amount}")
    public ResponseEntity<Object> sendMoney(
            @RequestBody @Valid SendMoneyRequest request) {

        if (request.money().isNegative()) {
            return ResponseEntity.badRequest().body("Money amount must be positive");
        }

        SendMoneyCommand command = new SendMoneyCommand(
                new Account.AccountId(request.sourceAccountId()),
                new Account.AccountId(request.targetAccountId()),
                request.money()
        );

        boolean success = sendMoneyUseCase.sendMoney(command);
        return success
                ? ResponseEntity.ok().build()
                : ResponseEntity.internalServerError().build();
    }
}

