package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.SendMoneyCommand;
import io.reflectoring.buckpal.application.port.out.AccountLock;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import io.reflectoring.buckpal.application.port.out.UpdateAccountStatePort;
import io.reflectoring.buckpal.common.UseCase;

import java.time.LocalDateTime;
import io.reflectoring.buckpal.application.domain.model.Account.AccountId;
import io.reflectoring.buckpal.application.port.in.SendMoneyUseCase;

@UseCase
public class SendMoneyService implements SendMoneyUseCase {

    private final LoadAccountPort loadAccountPort;
    private final AccountLock accountLock;
    private final UpdateAccountStatePort updateAccountStatePort;
    private final MoneyTransferProperties moneyTransferProperties;

    public SendMoneyService(
            LoadAccountPort loadAccountPort,
            AccountLock accountLock,
            UpdateAccountStatePort updateAccountStatePort,
            MoneyTransferProperties moneyTransferProperties) {
        this.loadAccountPort = loadAccountPort;
        this.accountLock = accountLock;
        this.updateAccountStatePort = updateAccountStatePort;
        this.moneyTransferProperties = moneyTransferProperties;
    }

    @Override
    public boolean sendMoney(SendMoneyCommand command) {
        Account sourceAccount = loadAccountPort.loadAccount(
                command.sourceAccountId(),
                LocalDateTime.now()
        );
        if (sourceAccount == null) {
            throw new AccountNotFoundException(command.sourceAccountId());
        }

        Account targetAccount = loadAccountPort.loadAccount(
                command.targetAccountId(),
                LocalDateTime.now()
        );
        if (targetAccount == null) {
            throw new AccountNotFoundException(command.targetAccountId());
        }

        accountLock.lockAccount(command.sourceAccountId());
        if (!sourceAccount.withdraw(command.money(), command.targetAccountId())) {
            accountLock.releaseAccount(command.sourceAccountId());
            throw new ThresholdExceededException(
                    sourceAccount.calculateBalance(),
                    moneyTransferProperties.getMaximumTransferThreshold()
            );
        }

        accountLock.lockAccount(command.targetAccountId());
        if (!targetAccount.deposit(command.money(), command.sourceAccountId())) {
            accountLock.releaseAccount(command.sourceAccountId());
            accountLock.releaseAccount(command.targetAccountId());
            throw new ThresholdExceededException(
                    targetAccount.calculateBalance(),
                    moneyTransferProperties.getMaximumTransferThreshold()
            );
        }

        updateAccountStatePort.updateActivities(sourceAccount);
        updateAccountStatePort.updateActivities(targetAccount);

        accountLock.releaseAccount(command.sourceAccountId());
        accountLock.releaseAccount(command.targetAccountId());

        return true;
    }
}

