package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.port.in.ExportTransactionHistoryQuery;
import io.reflectoring.buckpal.application.port.in.GetTransactionHistoryUseCase;
import io.reflectoring.buckpal.application.port.out.LoadTransactionHistoryPort;
import io.reflectoring.buckpal.common.UseCase;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.nio.charset.StandardCharsets;
import java.time.LocalDateTime;
import java.util.List;

@UseCase
public class TransactionHistoryService implements GetTransactionHistoryUseCase {

    private final LoadTransactionHistoryPort loadTransactionHistoryPort;

    public TransactionHistoryService(LoadTransactionHistoryPort loadTransactionHistoryPort) {
        this.loadTransactionHistoryPort = loadTransactionHistoryPort;
    }

    @Override
    public byte[] exportTransactionHistory(ExportTransactionHistoryQuery query) {
        List<Activity> activities = loadTransactionHistoryPort.getActivitiesByAccountAndDateRange(
                query.accountId(),
                query.startDate(),
                query.endDate()
        );

        try (ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
             OutputStreamWriter writer = new OutputStreamWriter(outputStream, StandardCharsets.UTF_8)) {

            writer.write("Source Account,Target Account,Amount,Timestamp\n");
            for (Activity activity : activities) {
                writer.write(String.format("%s,%s,%s,%s\n",
                        activity.getSourceAccountId().getValue(),
                        activity.getTargetAccountId().getValue(),
                        activity.getMoney().getAmount(),
                        activity.getTimestamp()));
            }
            writer.flush();
            return outputStream.toByteArray();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to generate CSV", e);
        }
    }
}

package io.reflectoring.buckpal.adapter.in.web;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.port.in.ExportTransactionHistoryQuery;
import io.reflectoring.buckpal.application.port.in.GetTransactionHistoryUseCase;
import io.reflectoring.buckpal.common.WebAdapter;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.time.LocalDateTime;

@WebAdapter
@RestController
@RequestMapping("/accounts")
public class TransactionHistoryController {

    private final GetTransactionHistoryUseCase getTransactionHistoryUseCase;

    public TransactionHistoryController(GetTransactionHistoryUseCase getTransactionHistoryUseCase) {
        this.getTransactionHistoryUseCase = getTransactionHistoryUseCase;
    }

    @GetMapping("/export")
    public ResponseEntity<byte[]> exportTransactionHistory(
            @RequestParam Long accountId,
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime startDate,
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime endDate) {

        byte[] csvData = getTransactionHistoryUseCase.exportTransactionHistory(
                new ExportTransactionHistoryQuery(
                        new Account.AccountId(accountId),
                        startDate,
                        endDate
                )
        );

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.parseMediaType("text/csv"));
        headers.setContentDispositionFormData("transaction_history.csv", "transaction_history.csv");
        headers.setCacheControl("must-revalidate, post-check=0, pre-check=0");

        return ResponseEntity.ok()
                .headers(headers)
                .body(csvData);
    }
}

package io.reflectoring.buckpal.adapter.out.persistence;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.port.out.LoadTransactionHistoryPort;
import io.reflectoring.buckpal.common.PersistenceAdapter;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Component;

import java.time.LocalDateTime;
import java.util.List;
import java.util.stream.Collectors;

@PersistenceAdapter
@Component
public class TransactionHistoryPersistenceAdapter implements LoadTransactionHistoryPort {

    private final SpringDataTransactionRepository transactionRepository;
    private final AccountMapper accountMapper;

    public TransactionHistoryPersistenceAdapter(
            SpringDataTransactionRepository transactionRepository,
            AccountMapper accountMapper) {
        this.transactionRepository = transactionRepository;
        this.accountMapper = accountMapper;
    }

    @Override
    public List<Activity> getActivitiesByAccountAndDateRange(
            Account.AccountId accountId,
            LocalDateTime startDate,
            LocalDateTime endDate) {

        return transactionRepository
                .findByOwnerAccountIdAndTimestampBetween(accountId.getValue(), startDate, endDate)
                .stream()
                .map(accountMapper::mapToDomainActivity)
                .collect(Collectors.toList());
    }
}

