    private Account(AccountId id, Money baselineBalance, ActivityWindow activityWindow, LocalDateTime lastActivityDate) {
        this.id = id;
        this.baselineBalance = baselineBalance;
        this.activityWindow = activityWindow;
        this.lastActivityDate = lastActivityDate;
    }

    public static Account withoutId(Money baselineBalance, ActivityWindow activityWindow) {
        return new Account(null, baselineBalance, activityWindow, null);
    }

    public static Account withId(AccountId id, Money baselineBalance, ActivityWindow activityWindow) {
        return new Account(id, baselineBalance, activityWindow, null);
    }

    public Optional<AccountId> getId() {
        return Optional.ofNullable(id);
    }

    public Money getBaselineBalance() {
        return baselineBalance;
    }

    public ActivityWindow getActivityWindow() {
        return activityWindow;
    }

    public LocalDateTime getLastActivityDate() {
        return lastActivityDate;
    }

    public boolean withdraw(Money money, AccountId targetAccountId) {
        if (this.calculateBalance().isGreaterThanOrEqualTo(money)) {
            Activity withdrawal = new Activity(
                    this.id,
                    this.id,
                    targetAccountId,
                    LocalDateTime.now(),
                    money
            );
            this.activityWindow.addActivity(withdrawal);
            return true;
        }
        return false;
