package io.reflectoring.buckpal.adapter.out.persistence;

import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.out.LoadAdminStatisticsPort;
import io.reflectoring.buckpal.common.PersistenceAdapter;
import org.springframework.jdbc.core.JdbcTemplate;
import java.time.LocalDate;

@PersistenceAdapter
public class AdminStatisticsPersistenceAdapter implements LoadAdminStatisticsPort {
    private final JdbcTemplate jdbcTemplate;

    public AdminStatisticsPersistenceAdapter(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }

    @Override
    public long countAccounts() {
        return jdbcTemplate.queryForObject(
                "SELECT COUNT(*) FROM account",
                Long.class
        );
    }

    @Override
    public Money getTotalTransfersToday() {
        Long totalAmount = jdbcTemplate.queryForObject(
                "SELECT COALESCE(SUM(amount), 0) FROM activity " +
                "WHERE timestamp >= ? AND timestamp < ?",
                Long.class,
                LocalDate.now().atStartOfDay(),
                LocalDate.now().plusDays(1).atStartOfDay()
        );
        return Money.of(totalAmount != null ? totalAmount : 0L);
    }
}

