import io.reflectoring.buckpal.application.port.in.GetTransferHistoryUseCase;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;

public class GetTransferHistoryService implements GetTransferHistoryUseCase {
    private final LoadAccountPort loadAccountPort;

    public GetTransferHistoryService(LoadAccountPort loadAccountPort) {
        this.loadAccountPort = loadAccountPort;
    }

    @Override
    public List<Activity> getTransferHistory(LocalDate startDate, LocalDate endDate) {
        return loadAccountPort.loadAllAccounts().stream()
                .flatMap(account -> account.getActivityWindow().getActivities().stream())
