import org.springframework.web.bind.annotation.RequestParam;
import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.port.in.GetTransferHistoryUseCase;
import io.reflectoring.buckpal.common.WebAdapter;
import io.reflectoring.buckpal.application.domain.model.Account;

@WebAdapter
public class TransferHistoryController {
    private final GetTransferHistoryUseCase getTransferHistoryUseCase;

    public TransferHistoryController(GetTransferHistoryUseCase getTransferHistoryUseCase) {
        this.getTransferHistoryUseCase = getTransferHistoryUseCase;
    }

    @GetMapping("/export/transfers")
    public ResponseEntity<byte[]> exportTransfers(
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate startDate,
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate endDate) {
        List<Activity> transfers = getTransferHistoryUseCase.getTransferHistory(startDate, endDate);
        String csv = generateCsv(transfers);
        byte[] csvBytes = csv.getBytes();
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.TEXT_PLAIN);
        headers.setContentDispositionFormData("transfers.csv", "transfers.csv");
        return ResponseEntity.ok().headers(headers).body(csvBytes);
    }

    private String generateCsv(List<Activity> transfers) {
        StringBuilder csv = new StringBuilder();
        csv.append("Source Account,Target Account,Amount,Timestamp\n");
        transfers.forEach(activity ->
            csv.append("%s,%s,%s,%s\n".formatted(
                activity.getSourceAccountId().getValue(),
                activity.getTargetAccountId().getValue(),
                activity.getMoney().getAmount(),
                activity.getTimestamp()
            ))
        );
        return csv.toString();
    }
}

