package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.AdminStats;
import io.reflectoring.buckpal.application.port.in.GetAdminStatsUseCase;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import java.math.BigInteger;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.util.List;
import java.util.stream.Collectors;

public class GetAdminStatsService implements GetAdminStatsUseCase {

    private final LoadAccountPort loadAccountPort;

    public GetAdminStatsService(LoadAccountPort loadAccountPort) {
        this.loadAccountPort = loadAccountPort;
    }

    @Override
    public AdminStats getAdminStats(LocalDate date) {
        LocalDateTime startOfDay = date.atStartOfDay();
        LocalDateTime endOfDay = date.atTime(LocalTime.MAX);

        List<Account> accounts = loadAccountPort.loadAllAccounts();
        long totalAccounts = accounts.size();

        Money totalTransferVolume = accounts.stream()
                .flatMap(account -> account.getActivityWindow().getActivities().stream())
                .filter(activity -> activity.getTimestamp().isAfter(startOfDay)
                        && activity.getTimestamp().isBefore(endOfDay)
                        && activity.getTargetAccountId() != null)
                .map(Activity::getMoney)
                .reduce(Money.ZERO, Money::add);

        return new AdminStats(totalAccounts, totalTransferVolume);
    }
}

