package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.AdminStats;
import io.reflectoring.buckpal.application.port.in.GetAdminStatsUseCase;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import io.reflectoring.buckpal.common.UseCase;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.List;

@UseCase
public class GetAdminStatsService implements GetAdminStatsUseCase {
    private final LoadAccountPort loadAccountPort;

    public GetAdminStatsService(LoadAccountPort loadAccountPort) {
        this.loadAccountPort = loadAccountPort;
    }

    @Override
    public AdminStats getAdminStats() {
        List<Long> accountIds = loadAccountPort.getAllAccountIds();
        long totalAccounts = accountIds.size();

        LocalDateTime startOfDay = LocalDate.now().atStartOfDay();
        LocalDateTime endOfDay = LocalDate.now().atTime(23, 59, 59);
        Money totalTransfersToday = Money.ZERO;

        for (Long accountId : accountIds) {
            var account = loadAccountPort.loadAccount(new io.reflectoring.buckpal.application.domain.model.Account.AccountId(accountId), endOfDay);
            var activities = account.getActivityWindow().getActivities();
            for (var activity : activities) {
                if (activity.getTimestamp().isAfter(startOfDay) && activity.getTimestamp().isBefore(endOfDay)) {
                    totalTransfersToday = totalTransfersToday.plus(activity.getMoney());
                }
            }
        }

        return new AdminStats(totalAccounts, totalTransfersToday);
    }
}

