package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Activity;
import io.reflectoring.buckpal.application.port.in.GetAccountActivitiesUseCase;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import io.reflectoring.buckpal.common.UseCase;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.Pageable;

import java.util.List;

@UseCase
public class GetAccountActivitiesService implements GetAccountActivitiesUseCase {

    private final LoadAccountPort loadAccountPort;

    public GetAccountActivitiesService(LoadAccountPort loadAccountPort) {
        this.loadAccountPort = loadAccountPort;
    }

    @Override
    public Page<Activity> getAccountActivities(Account.AccountId accountId, Pageable pageable) {
        Account account = loadAccountPort.loadAccount(accountId, null);
        List<Activity> activities = account.getActivityWindow().getActivities();
        int start = (int) pageable.getOffset();
        int end = Math.min((start + pageable.getPageSize()), activities.size());
        return new PageImpl<>(activities.subList(start, end), pageable, activities.size());
    }
}

