import io.reflectoring.buckpal.application.port.in.GetAccountLimitInfoUseCase;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import io.reflectoring.buckpal.common.UseCase;

@UseCase
public class GetAccountLimitInfoService implements GetAccountLimitInfoUseCase {

    private final LoadAccountPort loadAccountPort;

    public GetAccountLimitInfoService(LoadAccountPort loadAccountPort) {
        this.loadAccountPort = loadAccountPort;
    }

    @Override
    public GetAccountLimitInfoResponse getAccountLimitInfo(AccountId accountId) {
        Account account = loadAccountPort.loadAccount(accountId, null);
        Money balance = account.calculateBalance();
        Money availableBalance = account.getBaselineBalance().plus(balance);
        return new GetAccountLimitInfoResponse(balance, availableBalance);
    }
}

