package io.reflectoring.buckpal.adapter.in.web;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.SendMoneyCommand;
import io.reflectoring.buckpal.application.port.in.SendMoneyUseCase;
import io.reflectoring.buckpal.common.WebAdapter;
import jakarta.validation.Valid;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ModelAttribute;
import org.springframework.web.bind.annotation.PostMapping;
import io.reflectoring.buckpal.application.domain.model.Account.AccountId;

@Controller
@WebAdapter
public class SendMoneyController {

    private final SendMoneyUseCase sendMoneyUseCase;
    private final MoneyTransferLimit transferLimit;

    public SendMoneyController(SendMoneyUseCase sendMoneyUseCase, MoneyTransferLimit transferLimit) {
        this.sendMoneyUseCase = sendMoneyUseCase;
        this.transferLimit = transferLimit;
    }

    @GetMapping("accounts/send-money")
    public String loadSendMoneyForm(Model model) {
        model.addAttribute("sendMoneyForm", new SendMoneyForm());
        model.addAttribute("transferLimit", transferLimit.getLimit());
        return "send-money";
    }

    @PostMapping("accounts/send-money")
    public String sendMoney(@Valid @ModelAttribute SendMoneyForm form, Model model) {
        boolean success = sendMoneyUseCase.sendMoney(
                new SendMoneyCommand(
                        new Account.AccountId(form.getSourceAccountId()),
                        new Account.AccountId(form.getTargetAccountId()),
                        Money.of(form.getAmount())
                )
        );
        model.addAttribute("success", success);
        model.addAttribute("transferLimit", transferLimit.getLimit());
        model.addAttribute("exceedsLimit", form.getAmount() > transferLimit.getLimit());
        return "send-money";
    }

    public static class SendMoneyForm {
        private Long sourceAccountId;
        private Long targetAccountId;
        private Long amount;

        public Long getSourceAccountId() {
            return sourceAccountId;
        }

        public void setSourceAccountId(Long sourceAccountId) {
            this.sourceAccountId = sourceAccountId;
        }

        public Long getTargetAccountId() {
            return targetAccountId;
        }

        public void setTargetAccountId(Long targetAccountId) {
            this.targetAccountId = targetAccountId;
        }

        public Long getAmount() {
            return amount;
        }

        public void setAmount(Long amount) {
            this.amount = amount;
        }
    }

    public static class MoneyTransferLimit {
        private final Long limit;

        public MoneyTransferLimit(Long limit) {
            this.limit = limit;
        }

        public Long getLimit() {
            return limit;
        }
    }
}

