package io.reflectoring.buckpal.application.domain.service;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.GetAccountBalanceUseCase;
import io.reflectoring.buckpal.application.port.out.LoadAccountPort;
import io.reflectoring.buckpal.common.UseCase;
import io.reflectoring.buckpal.application.domain.model.Account.AccountId;
import io.reflectoring.buckpal.application.domain.service.MoneyTransferProperties;

@UseCase
public class GetAccountBalanceService implements GetAccountBalanceUseCase {
    private final LoadAccountPort loadAccountPort;
    private final MoneyTransferProperties moneyTransferProperties;

    public GetAccountBalanceService(LoadAccountPort loadAccountPort, MoneyTransferProperties moneyTransferProperties) {
        this.loadAccountPort = loadAccountPort;
        this.moneyTransferProperties = moneyTransferProperties;
    }

    @Override
    public GetAccountBalanceResponse getAccountBalance(GetAccountBalanceQuery query) {
        Account account = loadAccountPort.loadAccount(query.accountId(), null);
        Money balance = account.calculateBalance();
        Money availableBalance = calculateAvailableBalance(balance);
        return new GetAccountBalanceResponse(balance, availableBalance);
    }

    private Money calculateAvailableBalance(Money balance) {
        Money threshold = moneyTransferProperties.getMaximumTransferThreshold();
        return balance.getAmount().compareTo(threshold.getAmount()) > 0
                ? balance.minus(threshold)
                : Money.ZERO;
    }
}

