package io.reflectoring.buckpal.adapter.in.web;

import io.reflectoring.buckpal.application.domain.model.Account;
import io.reflectoring.buckpal.application.domain.model.Money;
import io.reflectoring.buckpal.application.port.in.SendMoneyCommand;
import io.reflectoring.buckpal.application.port.in.SendMoneyUseCase;
import io.reflectoring.buckpal.common.WebAdapter;
import jakarta.validation.Valid;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ModelAttribute;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import io.reflectoring.buckpal.application.domain.model.Account.AccountId;
import io.reflectoring.buckpal.application.domain.service.MoneyTransferProperties;

@Controller
@WebAdapter
@RequestMapping("/accounts/send")
public class SendMoneyController {

    private final SendMoneyUseCase sendMoneyUseCase;
    private final MoneyTransferProperties moneyTransferProperties;

    public SendMoneyController(SendMoneyUseCase sendMoneyUseCase, MoneyTransferProperties moneyTransferProperties) {
        this.sendMoneyUseCase = sendMoneyUseCase;
        this.moneyTransferProperties = moneyTransferProperties;
    }

    @GetMapping
    public String showSendMoneyForm(Model model) {
        model.addAttribute("sendMoneyForm", new SendMoneyForm());
        model.addAttribute("transferLimit", moneyTransferProperties.getMaximumTransferThreshold());
        return "sendMoney";
    }

    @PostMapping
    public String sendMoney(@Valid @ModelAttribute("sendMoneyForm") SendMoneyForm form) {
        sendMoneyUseCase.sendMoney(form.toCommand());
        return "redirect:/accounts";
    }

    public static class SendMoneyForm {
        private Account.AccountId sourceAccountId;
        private Account.AccountId targetAccountId;
        private Money amount;
        private boolean exceedsLimit;

        public Account.AccountId getSourceAccountId() {
            return sourceAccountId;
        }

        public void setSourceAccountId(Account.AccountId sourceAccountId) {
            this.sourceAccountId = sourceAccountId;
        }

        public Account.AccountId getTargetAccountId() {
            return targetAccountId;
        }

        public void setTargetAccountId(Account.AccountId targetAccountId) {
            this.targetAccountId = targetAccountId;
        }

        public Money getAmount() {
            return amount;
        }

        public void setAmount(Money amount) {
            this.amount = amount;
            this.exceedsLimit = amount != null && amount.isGreaterThan(moneyTransferProperties.getMaximumTransferThreshold());
        }

        public boolean isExceedsLimit() {
            return exceedsLimit;
        }

        public SendMoneyCommand toCommand() {
            return new SendMoneyCommand(sourceAccountId, targetAccountId, amount);
        }
    }
}

